class OAuthClient {
    constructor(clientId, redirectUri, scope) {
        this.clientId = clientId;
        this.redirectUri = redirectUri;
        this.scope = scope;
        this.accessToken = localStorage.getItem('accessToken');
        this.refreshToken = localStorage.getItem('refreshToken');
        this.tokenExpiry = localStorage.getItem('tokenExpiry');

        if (this.accessToken && this.tokenExpiry) {
            const now = new Date().getTime();
            if (now > parseInt(this.tokenExpiry)) {
                this.refreshAccessToken();
            }
        }
    }

    async authenticate() {
        const authUrl = `https://accounts.google.com/o/oauth2/v2/auth?response_type=code&client_id=${this.clientId}&redirect_uri=${encodeURIComponent(this.redirectUri)}&scope=${encodeURIComponent(this.scope)}`;
        window.location.href = authUrl;
    }

    async handleRedirect() {
        const urlParams = new URLSearchParams(window.location.search);
        const code = urlParams.get('code');
        if (code) {
            await this.exchangeCodeForTokens(code);
        }
    }

    async exchangeCodeForTokens(code) {
        const response = await fetch('https://oauth2.googleapis.com/token', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/x-www-form-urlencoded'
            },
            body: `code=${code}&client_id=${this.clientId}&redirect_uri=${encodeURIComponent(this.redirectUri)}&grant_type=authorization_code`
        });

        const data = await response.json();
        this.accessToken = data.access_token;
        this.refreshToken = data.refresh_token;
        this.tokenExpiry = new Date().getTime() + (data.expires_in * 1000);

        localStorage.setItem('accessToken', this.accessToken);
        localStorage.setItem('refreshToken', this.refreshToken);
        localStorage.setItem('tokenExpiry', this.tokenExpiry);

        window.history.replaceState({}, document.title, window.location.origin + window.location.pathname);
    }

    async refreshAccessToken() {
        const response = await fetch('https://oauth2.googleapis.com/token', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/x-www-form-urlencoded'
            },
            body: `refresh_token=${this.refreshToken}&client_id=${this.clientId}&grant_type=refresh_token`
        });

        const data = await response.json();
        this.accessToken = data.access_token;
        this.tokenExpiry = new Date().getTime() + (data.expires_in * 1000);

        localStorage.setItem('accessToken', this.accessToken);
        localStorage.setItem('tokenExpiry', this.tokenExpiry);
    }

    getAccessToken() {
        return this.accessToken;
    }
}

